// src/components/InternshipCard.jsx
import React from "react";

export default function InternshipCard({ internship, currentUser, onApply, isApplied }) {
  return (
    <div className="bg-white rounded-xl shadow p-4 mb-4">
      <h3 className="text-lg font-semibold">{internship.title}</h3>
      <p className="text-sm text-gray-600">{internship.company}</p>
      <p className="text-sm">{internship.category} | {internship.mode}</p>
      <p className="text-sm">{internship.location}</p>
      <p className="text-sm mt-2">{internship.description}</p>

      {currentUser.role === "student" && (
        <button
          onClick={() => onApply(internship._id)}
          className={`mt-3 px-4 py-2 text-white rounded ${
            isApplied ? "bg-gray-400 cursor-not-allowed" : "bg-green-600 hover:bg-green-700"
          }`}
          disabled={isApplied}
        >
          {isApplied ? "Applied" : "Apply"}
        </button>
      )}
    </div>
  );
}
